file.content:
:root {
  --bg: #f3f0ff;
  --panel: #ffffff;
  --surface: #faf9ff;
  --surface-strong: #f0edff;
  --text: #172033;
  --muted: #697386;
  --subtle: #8a93a5;
  --line: #e3def4;
  --line-strong: #cfc6ec;
  --blue: #5b5cf6;
  --blue-strong: #4b46e8;
  --blue-soft: #f0eeff;
  --purple-deep: #3f36c8;
  --purple-lilac: #8b7cf6;
  --green: #07825d;
  --orange: #b76b00;
  --red: #c43e52;
  --shadow-sm: 0 1px 2px rgba(16, 24, 40, 0.06);
  --shadow: 0 12px 32px rgba(63, 54, 200, 0.14);
  --radius: 8px;
  --radius-sm: 6px;
}

* { box-sizing: border-box; }

body {
  margin: 0;
  color: var(--text);
  background: var(--bg);
  font-family: Inter, -apple-system, BlinkMacSystemFont, "Segoe UI", "PingFang SC", sans-serif;
  letter-spacing: 0;
}

button, input, select, textarea {
  font: inherit;
}

button {
  min-height: 36px;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  color: var(--text);
  background: #fff;
  padding: 0 13px;
  cursor: pointer;
  transition: background .16s ease, border-color .16s ease, box-shadow .16s ease, transform .12s ease;
}

button:hover {
  border-color: var(--line-strong);
  background: #fafbff;
}

button:active {
  transform: translateY(1px);
}

button:focus-visible,
input:focus-visible,
select:focus-visible,
textarea:focus-visible {
  outline: 3px solid rgba(91, 92, 246, .2);
  outline-offset: 2px;
  border-color: var(--blue);
}

button.primary {
  border-color: var(--blue);
  background: var(--blue);
  color: #fff;
  box-shadow: 0 8px 18px rgba(91, 92, 246, .22);
}

button.primary:hover {
  background: #4b4dec;
}

input, select, textarea {
  width: 100%;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  background: #fff;
  color: var(--text);
  padding: 10px 11px;
  outline: none;
}

textarea {
  min-height: 126px;
  resize: vertical;
  line-height: 1.6;
}

.layout {
  display: grid;
  min-height: 100vh;
  grid-template-columns: 232px 1fr;
}

.sidebar {
  position: sticky;
  top: 0;
  height: 100vh;
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding: 16px 14px;
  background:
    linear-gradient(180deg, rgba(240, 238, 255, .98) 0%, rgba(246, 244, 255, .96) 58%, rgba(235, 241, 255, .9) 100%);
  border-right: 1px solid var(--line);
}

.brand {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 19px;
  padding: 2px 2px 8px;
}

.brand-mark {
  display: inline-grid;
  width: 24px;
  height: 24px;
  place-items: center;
  border-radius: 7px;
  color: #fff;
  background: linear-gradient(135deg, var(--blue), var(--purple-lilac));
  font-weight: 800;
}

.create-agent {
  width: 100%;
  min-height: 40px;
  color: #fff;
  border-color: var(--blue);
  background: var(--blue);
}

.side-section {
  display: grid;
  gap: 4px;
}

.side-section span {
  margin: 10px 8px 3px;
  font-size: 12px;
  color: var(--subtle);
}

.side-section button {
  width: 100%;
  justify-content: flex-start;
  text-align: left;
  border-color: transparent;
  background: transparent;
  color: #3b4253;
  min-height: 34px;
}

.side-section button.active,
.side-section button:hover {
  background: #fff;
  color: var(--blue);
  box-shadow: var(--shadow-sm);
}

.space-card {
  display: flex;
  align-items: center;
  gap: 8px;
  height: 34px;
  padding: 0 8px;
  border: 1px solid rgba(221, 227, 237, .8);
  border-radius: var(--radius-sm);
  background: rgba(255,255,255,.76);
  box-shadow: var(--shadow-sm);
}

.space-card small {
  color: var(--blue);
  background: #f0eeff;
  border: 1px solid #ded8ff;
  border-radius: 4px;
  padding: 1px 4px;
}

.space-icon {
  display: inline-grid;
  width: 22px;
  height: 22px;
  place-items: center;
  border-radius: 6px;
  color: #fff;
  background: var(--blue);
}

.profile {
  margin-top: auto;
  display: flex;
  align-items: center;
  gap: 8px;
  padding: 8px;
  border-top: 1px solid #dfe4ff;
}

.avatar {
  display: inline-block;
  width: 28px;
  height: 28px;
  border-radius: 50%;
  background: linear-gradient(135deg, #ffd1dc, #6ba5ff);
}

.workspace {
  margin: 10px;
  border: 1px solid var(--line);
  border-radius: 12px;
  background: #fff;
  min-width: 0;
  overflow: hidden;
  box-shadow: 0 1px 2px rgba(16, 24, 40, .04);
}

.page-head {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 16px;
  padding: 18px 24px 12px;
  background: #fff;
}

.title-row {
  display: flex;
  align-items: center;
  gap: 16px;
}

h1, h2, h3, p {
  margin-top: 0;
}

h1 {
  margin-bottom: 0;
  font-size: 20px;
  font-weight: 700;
}

.segmented {
  display: inline-flex;
  border: 1px solid var(--line);
  border-radius: var(--radius-sm);
  overflow: hidden;
  background: var(--surface);
}

.segmented button {
  height: 30px;
  border: 0;
  border-radius: 0;
}

.segmented button.active {
  color: var(--blue);
  background: #fff;
  box-shadow: inset 0 0 0 1px rgba(91, 92, 246, .5);
}

.search {
  position: relative;
  width: min(360px, 40vw);
}

.search span::before {
  content: "";
  position: absolute;
  width: 13px;
  height: 13px;
  left: 12px;
  top: 50%;
  transform: translateY(-50%);
  border: 1.8px solid #b8becf;
  border-radius: 50%;
}

.search span::after {
  content: "";
  position: absolute;
  width: 6px;
  height: 1.8px;
  left: 23px;
  top: 22px;
  background: #b8becf;
  transform: rotate(45deg);
}

.search input {
  height: 34px;
  padding-left: 34px;
}

.resource-tabs {
  display: flex;
  gap: 22px;
  padding: 0 24px;
  border-bottom: 1px solid var(--line);
  background: #fff;
}

.resource-tabs button {
  position: relative;
  min-height: 44px;
  border: 0;
  border-radius: 0;
  background: transparent;
  color: #4b5163;
  padding: 0 2px;
}

.resource-tabs button.active {
  color: var(--blue);
  font-weight: 700;
}

.resource-tabs button.active::after {
  content: "";
  position: absolute;
  left: 0;
  right: 0;
  bottom: 0;
  height: 3px;
  border-radius: 999px 999px 0 0;
  background: var(--blue);
}

.resource-tabs i {
  margin-left: 5px;
  color: #fff;
  background: var(--blue);
  border-radius: 999px;
  padding: 1px 5px;
  font-size: 10px;
  font-style: normal;
}

.skill-page {
  padding: 18px 24px 32px;
  background: linear-gradient(180deg, #fff 0%, #fcfbff 100%);
}

.skill-toolbar {
  display: flex;
  justify-content: space-between;
  align-items: center;
  gap: 14px;
  margin-bottom: 14px;
}

.toolbar-left,
.toolbar-right {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-wrap: wrap;
}

.metric-pill {
  display: inline-flex;
  align-items: center;
  gap: 7px;
  min-height: 36px;
  padding: 0 12px;
  border: 1px solid #ded8ff;
  border-radius: var(--radius-sm);
  background: var(--blue-soft);
  color: var(--blue);
}

.metric-pill span {
  color: #4b5163;
}

.toolbar-left select {
  width: 132px;
  height: 34px;
}

.icon-btn {
  width: 36px;
  padding: 0;
  display: inline-grid;
  place-items: center;
}

.icon-btn.active {
  color: var(--blue);
  border-color: #d8d0ff;
  background: var(--blue-soft);
}

.generator-strip {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 14px;
  margin-bottom: 18px;
  padding: 16px 18px;
  border: 1px solid #ded8ff;
  border-radius: var(--radius);
  background:
    linear-gradient(90deg, rgba(240, 238, 255, .96), rgba(255,255,255,.98)),
    radial-gradient(circle at top left, rgba(139, 124, 246, .14), transparent 42%);
  box-shadow: var(--shadow-sm);
}

.generator-strip.official {
  background: linear-gradient(90deg, #f5fffb, #fff);
  border-color: #daf5e9;
}

.generator-strip p {
  margin: 5px 0 0;
  color: var(--muted);
  line-height: 1.5;
}

.skill-grid {
  display: grid;
  grid-template-columns: repeat(3, minmax(292px, 1fr));
  gap: 16px;
}

.skill-card,
.skill-row {
  position: relative;
  border: 1px solid var(--line);
  border-radius: var(--radius);
  background: #fff;
  transition: border-color .16s, box-shadow .16s, transform .16s;
  box-shadow: var(--shadow-sm);
}

.card-hit {
  position: absolute;
  inset: 0;
  z-index: 1;
  width: 100%;
  height: 100%;
  border: 0;
  background: transparent;
  padding: 0;
}

.card-head,
.tag-row,
.card-meta,
.card-actions,
.row-actions,
.copy-id {
  position: relative;
  z-index: 2;
}

.skill-card:hover,
.skill-row:hover {
  border-color: #cbd2ee;
  box-shadow: 0 8px 28px rgba(35, 45, 90, .08);
  transform: translateY(-1px);
}

.skill-card {
  display: flex;
  min-height: 232px;
  flex-direction: column;
  padding: 17px;
}

.card-head {
  display: grid;
  grid-template-columns: 44px 1fr auto;
  gap: 12px;
  align-items: start;
}

.skill-icon {
  display: inline-grid;
  width: 40px;
  height: 40px;
  flex: 0 0 auto;
  place-items: center;
  border-radius: var(--radius);
  color: #fff;
  background: linear-gradient(135deg, var(--blue), var(--purple-lilac));
  font-weight: 800;
  box-shadow: 0 10px 18px rgba(91, 92, 246, .18);
}

.card-head h3,
.skill-row h3 {
  margin-bottom: 5px;
  font-size: 16px;
}

.copy-id {
  width: auto;
  height: auto;
  border: 0;
  padding: 0;
  color: var(--muted);
  background: transparent;
  font-size: 12px;
}

