  display: grid;
  align-content: start;
  gap: 24px;
  padding: 32px;
  border-left: 1px solid #e5e7eb;
  background: #fcfcfd;
  overflow: auto;
}

.rendered-skill {
  color: #172033;
}

.rendered-skill h1 {
  margin: 0 0 18px;
  font-size: 28px;
  font-weight: 700;
  line-height: 1.25;
}

.rendered-skill h2 {
  margin: 24px 0 12px;
  padding-bottom: 10px;
  border-bottom: 1px solid #111827;
  font-size: 17px;
  font-weight: 650;
}

.rendered-skill p {
  margin: 0 0 12px;
  color: #475467;
  font-size: 14px;
  line-height: 1.75;
}

.bullet-line::before {
  content: "- ";
}

.ordered-line {
  color: #344054;
}

.bundle-files {
  display: grid;
  gap: 12px;
  padding-top: 16px;
  border-top: 1px solid #e5e7eb;
}

.bundle-files header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 12px;
}

.bundle-files span {
  color: #667085;
  font-size: 12px;
}

.editor-assets {
  grid-template-columns: 1fr;
}

@media (max-width: 1180px) {
  .skill-grid { grid-template-columns: repeat(2, minmax(260px, 1fr)); }
  .skill-row { grid-template-columns: 44px 1fr; }
  .row-col, .row-actions { grid-column: 2; }
  .create-type-grid { grid-template-columns: repeat(2, minmax(240px, 1fr)); }
  .detail-grid-page { grid-template-columns: 1fr; }
  .skill-editor-shell { grid-template-columns: 280px minmax(0, 1fr); }
  .editor-split-view { grid-template-columns: 1fr; }
  .render-pane { border-left: 0; border-top: 1px solid #e5e7eb; }
}

@media (max-width: 820px) {
  .layout { grid-template-columns: 1fr; }
  .sidebar { position: static; height: auto; }
  .page-head, .skill-toolbar, .generator-strip { align-items: stretch; flex-direction: column; }
  .search { width: 100%; }
  .skill-grid, .two-col, .mode-tabs, .scan-box, .create-type-grid, .editor-layout, .detail-hero, .scan-progress { grid-template-columns: 1fr; }
  .split-editor, .modal-grid { grid-template-columns: 1fr; }
  .bundle-preview-pane { position: static; }
  .editor-side { position: static; }
  .detail-actions { justify-content: flex-start; }
  .method-modal { padding: 24px; }
  .method-option { grid-template-columns: 44px minmax(0, 1fr); }
  .method-chevron { display: none; }
  .skill-editor-shell { grid-template-columns: 1fr; grid-template-rows: auto auto minmax(0, 1fr); }
  .editor-topbar { flex-direction: column; align-items: stretch; padding: 14px; }
  .editor-meta-panel { border-right: 0; border-bottom: 1px solid #e5e7eb; }
  .editor-title strong { max-width: 100%; }
}

import {
  createSkillFromNaturalLanguage,
  filterSkills,
  getNextStatus,
  scanSkill,
  seedSkills,
  statusOrder
} from "../src/skills.js";

const storageKey = "br_skill_resource_library_v2";

const state = {
  page: "library",
  primaryTab: "space",
  resourceTab: "skill",
  skillView: "grid",
  keyword: "",
  status: "全部",
  source: "全部",
  createMode: "",
  editingId: "",
  detailId: "",
  detailTab: "overview",
  modal: "",
  importedFileName: "",
  skills: loadSkills()
};

let keywordTimer = null;

const resourceTabs = [
  { id: "knowledge", label: "知识库" },
  { id: "database", label: "数据库" },
  { id: "plugin", label: "插件库" },
  { id: "skill", label: "技能" }
];

const createTypes = [
  {
    id: "在线编写",
    title: "在线编写",
    subtitle: "支持自然语言生成",
    description: "进入完整编辑器后，可手写 Skill，也可在编辑过程中输入自然语言并点击生成。",
    assets: ["自然语言生成", "SKILL.md", "manifest.json", "schema"]
  },
  {
    id: "GitLab 拉取",
    title: "GitLab 拉取",
    subtitle: "团队协作",
    description: "选择 GitLab 服务和仓库，按 manifest.json、skill.yaml、SKILL.md 自动识别入口。",
    assets: ["manifest.json", "skill.yaml", "SKILL.md"]
  },
  {
    id: "导入技能包",
    title: "导入技能包",
    subtitle: "迁移已有资产",
    description: "先唤起上传窗口读取 md、json、yaml、zip，再进入同一个技能编辑器确认和发布。",
    assets: [".md", ".json", ".yaml", ".zip"]
  }
];

const sources = ["全部", "自然语言生成", "在线编写", "GitLab 拉取", "文件导入", "导入技能包", "官方复制", "官方维护"];

function loadSkills() {
  const saved = localStorage.getItem(storageKey);
  return saved ? JSON.parse(saved) : seedSkills;
}

function saveSkills() {
  localStorage.setItem(storageKey, JSON.stringify(state.skills));
}

function render() {
  document.querySelector("#app").innerHTML = `
    <div class="layout">
      ${sidebar()}
      <main class="workspace">
        ${pageContent()}
      </main>
    </div>
    ${state.modal ? createMethodModal() : ""}
  `;
  bind();
}

function pageContent() {
  if (state.page === "editor") return editorPage();
  if (state.page === "detail") return detailPage();
  return `${topChrome()}${resourceNavigation()}${resourceBody()}`;
}

function sidebar() {
  return `
    <aside class="sidebar">
      <div class="brand">
        <span class="brand-mark">B</span>
        <strong>百融百工</strong>
      </div>
      <button class="create-agent">+ 创建智能体</button>
      <nav class="side-section"><span>广场</span><button>探索广场</button></nav>
      <nav class="side-section"><span>应用</span><button>批量任务</button></nav>
      <div class="space-card"><span class="space-icon">J</span><strong>jingxiu.zhao</strong><small>所有者</small></div>
      <nav class="side-section">
        <span>创作中心</span>
        <button>工作台</button>
        <button class="active">资源库</button>
        <button>效果评测</button>
      </nav>
      <nav class="side-section">
        <span>运行中心</span>
        <button>发布管理</button>
        <button>线上观测</button>
        <button>自动优化</button>
      </nav>
      <nav class="side-section">
        <span>管理中心</span>
        <button>空间管理</button>
        <button>文档中心</button>
      </nav>
      <div class="profile"><span class="avatar"></span><strong>jingxiu.zhao</strong></div>
    </aside>
  `;
}

function topChrome() {
  return `
    <header class="page-head">
      <div class="title-row">
        <h1>资源库</h1>
        <div class="segmented" role="tablist">
          <button class="${state.primaryTab === "space" ? "active" : ""}" data-primary="space">空间资源库</button>
          <button class="${state.primaryTab === "public" ? "active" : ""}" data-primary="public">公开资源库</button>
        </div>
      </div>
      <label class="search">
        <span></span>
        <input id="keyword" value="${escapeHtml(state.keyword)}" placeholder="请输入关键词搜索" />
      </label>
    </header>
  `;
}

function resourceNavigation() {
  return `
    <div class="resource-tabs">
      ${resourceTabs.map(tab => `
        <button class="${state.resourceTab === tab.id ? "active" : ""}" data-resource="${tab.id}">
          ${tab.label}${tab.id === "skill" ? "<i>NEW</i>" : ""}
        </button>
      `).join("")}
    </div>
  `;
}

function resourceBody() {
  if (state.resourceTab !== "skill") return placeholderResource();
  return skillResource();
}

function placeholderResource() {
  const copy = {
    knowledge: ["知识库", "沉淀文档、FAQ 和业务知识，供 Agent 检索引用。"],
    database: ["数据库", "配置结构化数据源，支持查询和分析任务。"],
    plugin: ["插件库", "连接外部系统，执行查数、发通知、建工单等动作。"]
  }[state.resourceTab];
  return `
    <section class="empty-resource">
      <div>
        <span class="big-icon">${copy[0].slice(0, 1)}</span>
        <h2>${copy[0]}</h2>
        <p>${copy[1]}</p>
      </div>
    </section>
  `;
}

function skillResource() {
  const library = state.primaryTab === "public" ? "official" : "space";
  const skills = filterSkills(state.skills, {
    library,
    keyword: state.keyword,
    status: state.status,
    source: state.source
  });
  return `
    <section class="skill-page">
      <div class="skill-toolbar">
        <div class="toolbar-left">
          <div class="metric-pill"><strong>${skills.length}</strong><span>${library === "official" ? "官方技能" : "空间技能"}</span></div>
          <select id="statusFilter">${["全部", ...statusOrder].map(item => `<option ${state.status === item ? "selected" : ""}>${item}</option>`).join("")}</select>
          <select id="sourceFilter">${sources.map(item => `<option ${state.source === item ? "selected" : ""}>${item}</option>`).join("")}</select>
        </div>
        <div class="toolbar-right">
          <button data-action="batch">批量操作</button>
          ${library === "space" ? `<button class="primary" data-open-create-modal>+ 创建技能</button>` : ""}
          <button class="icon-btn ${state.skillView === "list" ? "active" : ""}" data-view-mode="list" title="列表视图">≡</button>
          <button class="icon-btn ${state.skillView === "grid" ? "active" : ""}" data-view-mode="grid" title="卡片视图">□</button>
        </div>
      </div>
      ${library === "space" ? "" : officialBanner()}
      ${skills.length ? `
        <div class="${state.skillView === "grid" ? "skill-grid" : "skill-list"}">
          ${skills.map(skill => state.skillView === "grid" ? skillCard(skill) : skillRow(skill)).join("")}
        </div>
      ` : emptySkills(library)}
    </section>
  `;
}

function officialBanner() {
  return `
    <section class="generator-strip official">
      <div>
        <strong>官方技能库</strong>
        <p>官方技能可直接引用，也可以复制到空间后进入完整编辑页定制。</p>
      </div>
      <button data-switch-space>查看空间技能</button>
    </section>
  `;
}

function skillCard(skill) {
  return `
    <article class="skill-card">
      <button class="card-hit" data-detail="${skill.id}" aria-label="查看 ${skill.name} 详情"></button>
      <div class="card-head">
        <span class="skill-icon">${skill.owner === "official" ? "官" : "S"}</span>
        <div>
          <h3>${skill.name}</h3>
          <button class="copy-id" data-copy="${skill.skillId}">${skill.skillId}</button>
        </div>
        ${statusBadge(skill.status)}
      </div>
      <p class="description">${skill.description}</p>
      <div class="tag-row">
        <span>${skill.source}</span>
        <span>${skill.category}</span>
        <span>${skill.assets.length} 个资产</span>
      </div>
      <div class="card-meta">
        <span>${skill.creator}</span>
        <span>智能体：${skill.agents}</span>
        <span>${skill.version}</span>
      </div>
      <div class="card-actions">${skillActions(skill)}</div>
    </article>
  `;
}

function skillRow(skill) {
  return `
    <article class="skill-row">
      <span class="skill-icon">${skill.owner === "official" ? "官" : "S"}</span>
      <div class="row-main">
        <h3>${skill.name} <button class="copy-id" data-copy="${skill.skillId}">${skill.skillId}</button></h3>
        <p>${skill.description}</p>
      </div>
      <div class="row-col">${skill.source}<br><small>${skill.category}</small></div>
      <div class="row-col">${statusBadge(skill.status)}<br><small>${skill.version}</small></div>
      <div class="row-actions">${skillActions(skill)}</div>
    </article>
  `;
}

function skillActions(skill) {
  if (skill.owner === "official") {
    return `
      <button data-detail="${skill.id}">详情</button>
      <button class="primary" data-copy-official="${skill.id}">复制到空间</button>
      <button data-reference="${skill.id}">直接引用</button>
    `;
  }
  const editable = `<button data-edit="${skill.id}">编辑</button>`;
  const publish = ["草稿", "扫描失败", "待发布", "已下架"].includes(skill.status) ? `<button class="primary" data-request-publish="${skill.id}">发布</button>` : "";
  const unpublish = skill.status === "已发布" ? `<button data-unpublish="${skill.id}">下架</button>` : "";
  return `
    <button data-detail="${skill.id}">详情</button>
    ${editable}
    ${publish}
    ${unpublish}
    <button data-remove="${skill.id}">删除</button>
  `;
}

function statusBadge(status) {
  const label = status === "扫描中" ? "安全审核中" : status;
  const tone = {
    "草稿": "neutral",
    "扫描中": "info",
    "扫描失败": "danger",
    "待发布": "warning",
    "已发布": "success",
    "已下架": "neutral"
  }[status] || "neutral";
  return `<span class="status ${tone}">${label}</span>`;
}

function emptySkills(library) {
  return `
    <section class="empty-state">
      <span class="big-icon">S</span>
      <h2>${library === "official" ? "暂无匹配的官方技能" : "还没有空间技能"}</h2>
      <p>${library === "official" ? "调整搜索或筛选条件，查看平台维护的标准能力。" : "点击创建，先在弹窗选择创建方式，再进入编辑页。"}</p>
      ${library === "space" ? `<button class="primary" data-open-create-modal>创建技能</button>` : ""}
    </section>
  `;
}

function createMethodModal() {
  return `
    <div class="modal-backdrop">
      <section class="method-modal">
        ${state.modal === "import" ? uploadPanel() : `
          <header class="method-head">
            <h2>创建技能</h2>
            <p>创建方式只决定初始内容来源。选择后都会进入技能编辑器，完成确认后再发布。</p>
          </header>
          <div class="method-list">
            ${createTypes.map(type => `
              <button class="method-option" data-start-create="${type.id}" aria-label="${type.title}">
                ${methodIcon(type.id)}
                <span class="method-copy">
                  <strong>${type.title}</strong>
                  <small>${createMethodSubtitle(type)}</small>
                </span>
                <span class="method-chevron" aria-hidden="true">›</span>
              </button>
            `).join("")}
          </div>
          <footer class="method-footer">
            <button data-close-modal>取消</button>
          </footer>
        `}
      </section>
    </div>
  `;
}

function createMethodSubtitle(type) {
  const subtitles = {
    "在线编写": "进入编辑器编写 skill.md / config.json，可随时用自然语言生成或补全内容。",
    "GitLab 拉取": "从已接入仓库读取技能包，识别入口文件后进入编辑器确认差异。",
    "导入技能包": "上传本地技能包，解析 Markdown、JSON、YAML、ZIP 后进入编辑器。"
  };
  return subtitles[type.id] || type.description;
}

function methodIcon(type) {
  const tone = {
    "在线编写": "primary",
    "GitLab 拉取": "orange",
    "导入技能包": "violet"
  }[type] || "primary";
  const icons = {
    "在线编写": `<path d="M15.5 5.5 18 8l-8.8 8.8-3.7 1.1 1.1-3.7 8.9-8.7Z"></path><path d="m13.7 7.3 3 3"></path><path d="M5 6.5 3.5 5 5 3.5"></path><path d="M8 3.5 9.5 5 8 6.5"></path>`,
    "GitLab 拉取": `<path d="m12 18 7-5-2.3-7.2-2.4 4.5H9.7L7.3 5.8 5 13l7 5Z"></path><path d="m9.7 10.3 2.3 7.2 2.3-7.2"></path>`,
    "导入技能包": `<path d="M12 16V5"></path><path d="m8 9 4-4 4 4"></path><path d="M5 15v3h14v-3"></path>`
  };
  return `
    <span class="method-icon ${tone}" aria-hidden="true">
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="1.7" stroke-linecap="round" stroke-linejoin="round">${icons[type]}</svg>
    </span>
  `;
}

function uploadPanel() {
  return `
    <form class="upload-panel" id="uploadForm">
      <header class="method-head upload-head">
        <h2>导入技能包</h2>
        <p>上传 Markdown、JSON、YAML 或 ZIP 技能文件包。系统读取入口文件后进入编辑器，你可以继续补全、校验和发布。</p>
      </header>
      <label class="upload-box">
        <input type="file" name="skillFile" accept=".md,.json,.yaml,.yml,.zip">
        <span>点击选择文件</span>
        <small>${state.importedFileName || "尚未选择文件"}</small>
      </label>
      <footer class="method-footer">
        <button type="button" data-close-modal>取消</button>
        <button class="primary">导入并编辑</button>
      </footer>
    </form>
  `;
}

function editorPage() {
  const skill = state.editingId ? state.skills.find(item => item.id === state.editingId) : draftForMode(state.createMode);
  const mode = state.createMode || skill?.source || "在线编写";
  return `
    <section class="skill-editor-page">
      <form id="editorForm" class="skill-editor-shell">
        <header class="editor-topbar">
          <div class="editor-title">
            <button type="button" class="back-icon" data-back-library aria-label="返回资源库">‹</button>
            <span class="topbar-divider"></span>
            <strong>编辑器：${escapeHtml(skill.name || "未命名技能")}</strong>
            ${statusBadge(skill.status || "草稿")}
          </div>
          <div class="editor-actions">
            <span class="publish-note">发布后自动安全审核</span>
            <button type="submit" data-save-draft>保存草稿</button>
            <button type="button" class="primary" data-save-publish>发布</button>
          </div>
        </header>
        <aside class="editor-meta-panel">
          <section>
            <h2>基础信息</h2>
            <label>技能名称<input name="name" value="${escapeAttr(skill.name)}"></label>
            <label>Skill ID<input name="skillId" value="${escapeAttr(skill.skillId)}" ${state.editingId ? "" : ""}></label>
            <label>描述<textarea name="description" placeholder="请输入技能描述...">${escapeHtml(skill.description)}</textarea></label>
          </section>
          ${editorModePanel(mode, skill)}
        </aside>
        <main class="editor-workbench">
          <nav class="file-tabs" aria-label="技能文件">
            <button type="button" class="active">skill.md</button>
            <button type="button">config.json</button>
          </nav>
          <div class="editor-split-view">
            <section class="source-pane">
              <textarea class="code-editor" name="content" aria-label="skill.md 内容">${escapeHtml(skill.content)}</textarea>
            </section>
            <aside class="render-pane">
              <div class="rendered-skill">
                ${renderMarkdownPreview(skill)}
              </div>
              <div class="bundle-files">
                <header>
                  <strong>Skill Bundle</strong>
                  <span>${skill.assets.length} 个文件</span>
                </header>
                <div class="asset-tree editor-assets">
                  ${skill.assets.map(asset => `<span>${asset}</span>`).join("")}
                </div>
              </div>
            </aside>
          </div>
        </main>
      </form>
    </section>
  `;
}

function editorModePanel(mode, skill) {
  if (mode === "在线编写" || mode === "官方复制") {
    return `
      <section class="ai-panel">
        <h2>自然语言生成</h2>
        <label>业务需求<textarea name="prompt" placeholder="描述任务目标、适用场景、输入输出、约束规则">${escapeHtml(skill.description)}</textarea></label>
        <button type="button" class="primary full" data-generate-skill>生成 / 更新 Skill 内容</button>
      </section>
    `;
  }
  if (mode === "GitLab 拉取") {
    return `
      <section class="ai-panel">
        <h2>仓库来源</h2>
        <label>GitLab 服务器<select><option>gitlab.cn.example.com</option></select></label>
        <label>仓库<select><option>brclaw/skills/policy-qa</option><option>ops/skills/customer-care</option></select></label>
      </section>
    `;
  }
  return `
    <section class="ai-panel">
      <h2>导入来源</h2>
      <label>已上传文件<input value="${escapeAttr(state.importedFileName || "customer_service_qa.zip")}" readonly></label>
    </section>
  `;
}

function renderMarkdownPreview(skill) {
  const lines = String(skill.content || "").split("\n");
  const html = lines.map(line => {
    if (line.startsWith("# ")) return `<h1>${escapeHtml(line.slice(2))}</h1>`;
    if (line.startsWith("## ")) return `<h2>${escapeHtml(line.slice(3))}</h2>`;
    if (/^\d+\.\s/.test(line)) return `<p class="ordered-line">${escapeHtml(line)}</p>`;
    if (line.startsWith("- ")) return `<p class="bullet-line">${escapeHtml(line.slice(2))}</p>`;
    if (!line.trim()) return "";
    return `<p>${escapeHtml(line)}</p>`;
  }).join("");
  return `
    <h1>${escapeHtml(skill.name || "未命名技能")}</h1>
    <h2>技能说明</h2>
    <p>${escapeHtml(skill.description)}</p>
    ${html}
  `;
}

function draftForMode(mode) {
  if (mode === "在线编写") return {
    ...createSkillFromNaturalLanguage("客户投诉处理"),
    name: "客户投诉处理 Skill",
    skillId: "complaint_handling_skill",
    source: "在线编写",
    description: "根据投诉内容判断问题类型、优先级和处理流程。",
    content: `/when_to_use
当用户需要处理客户投诉、判断优先级或生成处理建议时使用。

