  return {
    ...createSkillFromNaturalLanguage("导入技能包"),
    name: state.importedFileName ? `${state.importedFileName.replace(/\.[^.]+$/, "")} Skill` : "导入技能草稿",
    skillId: state.importedFileName ? `${state.importedFileName.replace(/\.[^.]+$/, "").toLowerCase().replace(/[^a-z0-9_-]+/g, "_")}_skill` : "imported_skill_draft",
    source: "导入技能包",
    description: `从 ${state.importedFileName || "customer_service_qa.zip"} 解析出的标准技能包。`,
    assets: ["manifest.json", "SKILL.md", "schemas/input.schema.json", "schemas/output.schema.json"]
  };
}

function modeSpecificEditor(mode, skill) {
  if (mode === "在线编写" || mode === "官方复制") {
    return `
      <section class="editor-section hero-editor">
        <h2>AI 辅助生成</h2>
        <label>业务需求描述<textarea name="prompt" placeholder="描述任务目标、适用场景、输入输出、约束规则">${escapeHtml(skill.description)}</textarea></label>
        <div class="quality-check">
          <strong>生成质量检查</strong>
          <span>适用场景</span><span>输入要求</span><span>输出结构</span><span>约束规则</span><span>风险提示</span>
        </div>
        <button type="button" class="primary" data-generate-skill>生成 / 更新 Skill 内容</button>
      </section>
    `;
  }
  if (mode === "GitLab 拉取") {
    return `
      <section class="editor-section hero-editor">
        <h2>GitLab 仓库</h2>
        <div class="two-col">
          <label>GitLab 服务器<select><option>gitlab.cn.example.com</option></select></label>
          <label>仓库<select><option>brclaw/skills/policy-qa</option><option>ops/skills/customer-care</option></select></label>
        </div>
        <div class="quality-check"><strong>识别优先级</strong><span>manifest.json</span><span>skill.yaml</span><span>SKILL.md</span><span>.skill/SKILL.md</span></div>
      </section>
    `;
  }
  if (mode === "导入技能包") {
    return `
      <section class="editor-section hero-editor">
        <h2>导入解析结果</h2>
        <label>已上传文件<input value="${escapeAttr(state.importedFileName || "customer_service_qa.zip")}"></label>
        <div class="quality-check"><strong>已解析</strong><span>manifest.json</span><span>SKILL.md</span><span>schema</span><span>examples</span></div>
      </section>
    `;
  }
  return `
    <section class="editor-section hero-editor">
      <h2>在线编写模板</h2>
      <p>从标准 Skill 模板开始维护声明块。保存草稿后可发布进入安全审核。</p>
    </section>
  `;
}

function detailPage() {
  const skill = state.skills.find(item => item.id === state.detailId);
  if (!skill) return notFoundPage();
  const tabs = [
    ["overview", "概览"],
    ["content", "技能内容"],
    ["assets", "资产包"],
    ["scan", "安全审核"],
    ["refs", "引用关系"],
    ["logs", "调用记录"]
  ];
  return `
    <section class="detail-page">
      ${flowHeader("技能详情", "完整查看基础信息、资产包、安全审核、引用关系和调用记录。", "返回资源库")}
      <div class="detail-hero">
        <span class="skill-icon">${skill.owner === "official" ? "官" : "S"}</span>
        <div>
          <small>${skill.source} · ${skill.category}</small>
          <h1>${skill.name}</h1>
          <button class="copy-id" data-copy="${skill.skillId}">${skill.skillId}</button>
          <p>${skill.description}</p>
        </div>
        <div class="detail-actions">
          ${statusBadge(skill.status)}
          ${skill.owner === "space" ? `<button data-edit="${skill.id}">编辑</button>${["草稿", "扫描失败", "待发布", "已下架"].includes(skill.status) ? `<button class="primary" data-request-publish="${skill.id}">发布</button>` : ""}` : `<button class="primary" data-copy-official="${skill.id}">复制到空间</button>`}
        </div>
      </div>
      <div class="detail-tabs">
        ${tabs.map(([id, label]) => `<button class="${state.detailTab === id ? "active" : ""}" data-detail-tab="${id}">${label}</button>`).join("")}
      </div>
      ${detailTabContent(skill)}
    </section>
  `;
}

function detailTabContent(skill) {
  if (state.detailTab === "content") {
    return `<section class="detail-panel"><h2>结构化声明</h2><pre>${escapeHtml(skill.content)}</pre></section>`;
  }
  if (state.detailTab === "assets") {
    return `<section class="detail-panel"><h2>资产包文件</h2><div class="asset-tree">${skill.assets.map(asset => `<span>${asset}</span>`).join("")}</div></section>`;
  }
  if (state.detailTab === "scan") {
    return `
      <section class="detail-panel">
        <h2>安全审核</h2>
        <div class="scan-progress ${skill.status === "扫描中" ? "running" : ""}">
          <div><b>1</b><span>提交发布</span></div>
          <div><b>2</b><span>安全审核</span></div>
          <div><b>3</b><span>自动发布</span></div>
        </div>
        <div class="scan-box">
          <strong>${skill.scan.result}</strong>
          <span>风险等级：${skill.scan.level}</span>
          <span>风险项：${skill.scan.issues}</span>
          <span>${skill.scan.time}</span>
        </div>
      </section>
    `;
  }
  if (state.detailTab === "refs") {
    return `<section class="detail-panel"><h2>引用关系</h2><div class="data-table"><div><b>Agent</b><b>版本</b><b>状态</b></div><div><span>客服助手</span><span>${skill.version}</span><span>已启用</span></div><div><span>运营质检 Agent</span><span>${skill.version}</span><span>已启用</span></div></div></section>`;
  }
  if (state.detailTab === "logs") {
    return `<section class="detail-panel"><h2>调用记录</h2><div class="data-table"><div><b>时间</b><b>调用方式</b><b>结果</b></div><div><span>今天 14:30</span><span>自动判断</span><span>成功 1.2s</span></div><div><span>今天 13:54</span><span>/skill_id</span><span>成功 0.9s</span></div></div></section>`;
  }
  return `
    <section class="detail-grid-page">
      <div class="detail-panel">
        <h2>基础信息</h2>
        <div class="detail-grid">
          <span>状态</span><strong>${skill.status === "扫描中" ? "安全审核中" : skill.status}</strong>
          <span>版本</span><strong>${skill.version}</strong>
          <span>创建人</span><strong>${skill.creator}</strong>
          <span>引用 Agent</span><strong>${skill.agents}</strong>
          <span>更新时间</span><strong>${skill.updatedAt}</strong>
        </div>
      </div>
      <div class="detail-panel">
        <h2>发布链路</h2>
        <div class="scan-progress ${skill.status === "扫描中" ? "running" : ""}">
          <div><b>1</b><span>点击发布</span></div>
          <div><b>2</b><span>安全审核</span></div>
          <div><b>3</b><span>通过后自动发布</span></div>
        </div>
      </div>
    </section>
  `;
}

function flowHeader(title, subtitle, backLabel) {
  return `
    <header class="flow-head">
      <button data-back-library>← ${backLabel}</button>
      <div>
        <h1>${title}</h1>
        <p>${subtitle}</p>
      </div>
    </header>
  `;
}

function notFoundPage() {
  return `<section class="empty-resource"><div><h2>没有找到技能</h2><button data-back-library>返回资源库</button></div></section>`;
}

function bind() {
  document.querySelectorAll("[data-primary]").forEach(button => button.onclick = () => {
    state.primaryTab = button.dataset.primary;
    state.status = "全部";
    state.source = "全部";
    render();
  });
  document.querySelectorAll("[data-resource]").forEach(button => button.onclick = () => {
    state.resourceTab = button.dataset.resource;
    render();
  });
  document.querySelector("#keyword")?.addEventListener("input", event => {
    const value = event.target.value;
    clearTimeout(keywordTimer);
    keywordTimer = setTimeout(() => {
      state.keyword = value;
      render();
    }, 180);
  });
  document.querySelector("#statusFilter")?.addEventListener("change", event => {
    state.status = event.target.value;
    render();
  });
  document.querySelector("#sourceFilter")?.addEventListener("change", event => {
    state.source = event.target.value;
    render();
  });
  document.querySelectorAll("[data-view-mode]").forEach(button => button.onclick = () => {
    state.skillView = button.dataset.viewMode;
    render();
  });
  document.querySelectorAll("[data-open-create-modal]").forEach(button => button.onclick = () => {
    state.modal = "method";
    render();
  });
  document.querySelectorAll("[data-start-create]").forEach(button => button.onclick = () => {
    if (button.dataset.startCreate === "导入技能包") {
      state.modal = "import";
      render();
      return;
    }
    state.createMode = button.dataset.startCreate;
    state.editingId = "";
    state.modal = "";
    state.page = "editor";
    render();
  });
  document.querySelectorAll("[data-close-modal]").forEach(button => button.onclick = () => {
    state.modal = "";
    render();
  });
  document.querySelector("[name='skillFile']")?.addEventListener("change", event => {
    state.importedFileName = event.target.files?.[0]?.name || "";
    render();
  });
  document.querySelector("#uploadForm")?.addEventListener("submit", event => {
    event.preventDefault();
    state.importedFileName = state.importedFileName || "customer_service_qa.zip";
    state.createMode = "导入技能包";
    state.editingId = "";
    state.modal = "";
    state.page = "editor";
    toast("技能包已读取，请在编辑页确认解析结果");
    render();
  });
  document.querySelectorAll("[data-back-library]").forEach(button => button.onclick = () => {
    state.page = "library";
    state.detailId = "";
    state.editingId = "";
    render();
  });
  document.querySelectorAll("[data-detail]").forEach(button => button.onclick = () => {
    state.detailId = button.dataset.detail;
    state.detailTab = "overview";
    state.page = "detail";
    render();
  });
  document.querySelectorAll("[data-detail-tab]").forEach(button => button.onclick = () => {
    state.detailTab = button.dataset.detailTab;
    render();
  });
  document.querySelectorAll("[data-edit]").forEach(button => button.onclick = () => {
    const skill = state.skills.find(item => item.id === button.dataset.edit);
    if (!skill) return;
    state.editingId = skill.id;
    state.createMode = skill.source;
    state.page = "editor";
    render();
  });
  document.querySelector("#editorForm")?.addEventListener("submit", event => {
    event.preventDefault();
    saveEditor(false);
  });
  document.querySelector("[data-save-publish]")?.addEventListener("click", () => {
    const id = saveEditor(true);
    requestPublish(id);
  });
  document.querySelector("[data-generate-skill]")?.addEventListener("click", () => {
    const prompt = document.querySelector("[name='prompt']")?.value || "";
    const generated = createSkillFromNaturalLanguage(prompt);
    document.querySelector("[name='name']").value = generated.name;
    document.querySelector("[name='skillId']").value = generated.skillId;
    document.querySelector("[name='description']").value = generated.description;
    document.querySelector("[name='content']").value = generated.content;
    toast("已根据自然语言生成 Skill 内容");
  });
  document.querySelectorAll("[data-copy]").forEach(button => button.onclick = () => copyId(button.dataset.copy));
  document.querySelectorAll("[data-request-publish]").forEach(button => button.onclick = () => requestPublish(button.dataset.requestPublish));
  document.querySelectorAll("[data-unpublish]").forEach(button => button.onclick = () => updateStatus(button.dataset.unpublish, "unpublish", "技能已下架"));
  document.querySelectorAll("[data-remove]").forEach(button => button.onclick = () => removeSkill(button.dataset.remove));
  document.querySelectorAll("[data-copy-official]").forEach(button => button.onclick = () => copyOfficial(button.dataset.copyOfficial));
  document.querySelectorAll("[data-reference]").forEach(button => button.onclick = () => toast("已引用官方技能，可在 Agent 资源配置中使用"));
  document.querySelector("[data-switch-space]")?.addEventListener("click", () => {
    state.primaryTab = "space";
    render();
  });
  document.querySelector("[data-action='batch']")?.addEventListener("click", () => toast("可批量发布、下架或删除筛选结果"));
}

function saveEditor(silent = false) {
  const form = Object.fromEntries(new FormData(document.querySelector("#editorForm")));
  let skill = state.editingId ? state.skills.find(item => item.id === state.editingId) : null;
  if (!skill) {
    skill = draftForMode(state.createMode);
    skill.id = `sk-${Date.now()}`;
    state.skills = [skill, ...state.skills];
    state.editingId = skill.id;
  }
  skill.name = form.name;
  skill.skillId = form.skillId;
  skill.description = form.description;
  skill.content = form.content;
  skill.source = state.createMode || skill.source;
  skill.status = skill.status === "已发布" ? "草稿" : skill.status;
  skill.updatedAt = "刚刚";
  saveSkills();
  if (!silent) toast("草稿已保存");
  return skill.id;
}

function requestPublish(id) {
  const skill = state.skills.find(item => item.id === id);
  if (!skill) return;
  skill.status = getNextStatus(skill.status, "request_publish");
  skill.scan = { level: "-", issues: 0, result: "审核中", time: "刚刚" };
  skill.updatedAt = "刚刚";
  saveSkills();
  state.page = "detail";
  state.detailId = id;
  state.detailTab = "scan";
  toast("已提交发布，正在进行安全审核");
  render();
  setTimeout(() => {
    const result = scanSkill(skill);
    skill.status = result.summary.passed ? getNextStatus("扫描中", "scan_pass") : getNextStatus("扫描中", "scan_fail");
    skill.scan = result.scan;
    skill.version = skill.status === "已发布" ? nextVersion(skill.version) : skill.version;
    skill.updatedAt = "刚刚";
    saveSkills();
    toast(result.summary.passed ? "安全审核通过，技能已自动发布" : "安全审核未通过，请修复后再发布");
    render();
  }, 900);
}

function nextVersion(version) {
  const match = String(version || "v0.0.0").match(/^v(\d+)\.(\d+)\.(\d+)$/);
  if (!match) return "v1.0.0";
  return `v${match[1]}.${match[2]}.${Number(match[3]) + 1}`;
}

function updateStatus(id, action, message) {
  const skill = state.skills.find(item => item.id === id);
  if (!skill) return;
  skill.status = getNextStatus(skill.status, action);
  skill.updatedAt = "刚刚";
  saveSkills();
  toast(message);
  render();
}

function removeSkill(id) {
  const skill = state.skills.find(item => item.id === id);
  if (!skill) return;
  if (skill.agents > 0 && skill.status === "已发布") {
    toast("已被 Agent 引用的技能需先下架或解除引用");
    return;
  }
  state.skills = state.skills.filter(item => item.id !== id);
  state.page = "library";
  state.detailId = "";
  saveSkills();
  toast("技能已删除");
  render();
}

function copyOfficial(id) {
  const original = state.skills.find(item => item.id === id);
  if (!original) return;
  const copy = {
    ...original,
    id: `sk-${Date.now()}`,
    owner: "space",
    source: "官方复制",
    status: "草稿",
    skillId: `${original.skillId}_copy`,
    name: `${original.name} 副本`,
    agents: 0,
    creator: "jingxiu.zhao",
    updatedAt: "刚刚"
  };
  state.skills = [copy, ...state.skills];
  state.primaryTab = "space";
  state.page = "editor";
  state.editingId = copy.id;
  state.createMode = copy.source;
  saveSkills();
  toast("已复制到空间，请在编辑页确认后发布");
  render();
}

async function copyId(text) {
  await navigator.clipboard?.writeText(text);
  toast(`已复制 ${text}`);
}

function toast(text) {
  const el = document.createElement("div");
  el.className = "toast";
  el.textContent = text;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 2400);
}

function escapeHtml(text) {
  return String(text || "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function escapeAttr(text) {
  return escapeHtml(text).replaceAll("'", "&#39;");
}

render();

