function bind() {
  document.querySelectorAll("[data-primary]").forEach(button => button.onclick = () => {
    state.primaryTab = button.dataset.primary;
    state.status = "全部";
    state.source = "全部";
    render();
  });
  document.querySelectorAll("[data-resource]").forEach(button => button.onclick = () => {
    state.resourceTab = button.dataset.resource;
    render();
  });
  document.querySelector("#keyword")?.addEventListener("input", event => {
    const value = event.target.value;
    clearTimeout(keywordTimer);
    keywordTimer = setTimeout(() => {
      state.keyword = value;
      render();
    }, 180);
  });
  document.querySelector("#statusFilter")?.addEventListener("change", event => {
    state.status = event.target.value;
    render();
  });
  document.querySelector("#sourceFilter")?.addEventListener("change", event => {
    state.source = event.target.value;
    render();
  });
  document.querySelectorAll("[data-view-mode]").forEach(button => button.onclick = () => {
    state.skillView = button.dataset.viewMode;
    render();
  });
  document.querySelectorAll("[data-open-create-modal]").forEach(button => button.onclick = () => {
    state.modal = "method";
    render();
  });
  document.querySelectorAll("[data-start-create]").forEach(button => button.onclick = () => {
    if (button.dataset.startCreate === "导入技能包") {
      state.modal = "import";
      render();
      return;
    }
    state.createMode = button.dataset.startCreate;
    state.editingId = "";
    state.modal = "";
    state.page = "editor";
    render();
  });
  document.querySelectorAll("[data-close-modal]").forEach(button => button.onclick = () => {
    state.modal = "";
    render();
  });
  document.querySelector("[name='skillFile']")?.addEventListener("change", event => {
    const file = event.target.files?.[0];
    state.importedFileName = file?.name || "";
    const errEl = document.querySelector("#uploadError");
    if (file && !validateImportFile(file.name, file.size).valid) {
      errEl.textContent = validateImportFile(file.name, file.size).error;
      state.importedFileName = "";
    } else if (errEl) {
      errEl.textContent = "";
    }
    render();
  });
  document.querySelector("#uploadForm")?.addEventListener("submit", event => {
    event.preventDefault();
    const fileInput = document.querySelector("[name='skillFile']");
    const file = fileInput?.files?.[0];
    if (file) {
      const check = validateImportFile(file.name, file.size);
      if (!check.valid) {
        document.querySelector("#uploadError").textContent = check.error;
        return;
      }
    }
    state.importedFileName = state.importedFileName || "customer_service_qa.zip";
    state.createMode = "导入技能包";
    state.editingId = "";
    state.modal = "";
    state.page = "editor";
    toast("技能包已读取，请在编辑页确认解析结果");
    render();
  });
  document.querySelectorAll("[data-back-library]").forEach(button => button.onclick = () => {
    state.page = "library";
    state.detailId = "";
    state.editingId = "";
    render();
  });
  document.querySelectorAll("[data-detail]").forEach(button => button.onclick = () => {
    state.detailId = button.dataset.detail;
    state.detailTab = "overview";
    state.page = "detail";
    render();
  });
  document.querySelectorAll("[data-detail-tab]").forEach(button => button.onclick = () => {
    state.detailTab = button.dataset.detailTab;
    render();
  });
  document.querySelectorAll("[data-edit]").forEach(button => button.onclick = () => {
    const skill = state.skills.find(item => item.id === button.dataset.edit);
    if (!skill) return;
    state.editingId = skill.id;
    state.createMode = skill.source;
    state.page = "editor";
    render();
  });
  document.querySelector("[name='skillId']")?.addEventListener("input", event => {
    const errorEl = document.querySelector("#skillIdError");
    const existingIds = state.skills.filter(s => s.id !== state.editingId).map(s => s.skillId);
    const result = validateSkillId(event.target.value, existingIds);
    if (!result.valid && event.target.value.length > 0) {
      errorEl.textContent = result.error;
      event.target.setCustomValidity(result.error);
    } else {
      errorEl.textContent = "";
      event.target.setCustomValidity("");
    }
  });
  document.querySelector("#editorForm")?.addEventListener("submit", event => {
    event.preventDefault();
    saveEditor(false);
  });
  document.querySelector("[data-save-publish]")?.addEventListener("click", () => {
    const id = saveEditor(true);
    requestPublish(id);
  });
  document.querySelector("[data-generate-skill]")?.addEventListener("click", () => {
    const prompt = document.querySelector("[name='prompt']")?.value || "";
    const generated = createSkillFromNaturalLanguage(prompt);
    document.querySelector("[name='name']").value = generated.name;
    document.querySelector("[name='skillId']").value = generated.skillId;
    document.querySelector("[name='description']").value = generated.description;
    document.querySelector("[name='content']").value = generated.content;
    toast("已根据自然语言生成 Skill 内容");
  });
  document.querySelectorAll("[data-copy]").forEach(button => button.onclick = () => copyId(button.dataset.copy));
  document.querySelectorAll("[data-request-publish]").forEach(button => button.onclick = () => requestPublish(button.dataset.requestPublish));
  document.querySelectorAll("[data-unpublish]").forEach(button => button.onclick = () => updateStatus(button.dataset.unpublish, "unpublish", "技能已下架"));
  document.querySelectorAll("[data-remove]").forEach(button => button.onclick = () => removeSkill(button.dataset.remove));
  document.querySelectorAll("[data-copy-official]").forEach(button => button.onclick = () => copyOfficial(button.dataset.copyOfficial));
  document.querySelectorAll("[data-reference]").forEach(button => button.onclick = () => toast("已引用官方技能，可在 Agent 资源配置中使用"));
  document.querySelector("[data-switch-space]")?.addEventListener("click", () => {
    state.primaryTab = "space";
    render();
  });
  document.querySelector("[data-action='batch']")?.addEventListener("click", () => toast("可批量发布、下架或删除筛选结果"));
}

function saveEditor(silent = false) {
  const form = Object.fromEntries(new FormData(document.querySelector("#editorForm")));
  let skill = state.editingId ? state.skills.find(item => item.id === state.editingId) : null;
  if (!skill) {
    skill = draftForMode(state.createMode);
    skill.id = `sk-${Date.now()}`;
    state.skills = [skill, ...state.skills];
    state.editingId = skill.id;
  }
  skill.name = form.name;
  skill.skillId = form.skillId;
  skill.description = form.description;
  skill.content = form.content;
  skill.source = state.createMode || skill.source;
  if (skill.status === "已发布") {
    skill.status = "草稿变更";
  }
  skill.updatedAt = "刚刚";
  saveSkills();
  if (!silent) toast("草稿已保存");
  return skill.id;
}

function requestPublish(id) {
  const skill = state.skills.find(item => item.id === id);
  if (!skill) return;
  const publishCheck = validatePublishReady(skill);
  if (!publishCheck.ready) {
    toast(`发布前需补齐声明块：${publishCheck.missing.join("、")}`);
    return;
  }
  skill.status = getNextStatus(skill.status, "request_publish");
  skill.scan = { level: "-", issues: 0, result: "审核中", time: "刚刚" };
  skill.updatedAt = "刚刚";
  saveSkills();
  state.page = "detail";
  state.detailId = id;
  state.detailTab = "scan";
  toast("已提交发布，正在进行安全审核");
  render();
  setTimeout(() => {
    const result = scanSkill(skill);
    skill.status = result.summary.passed ? getNextStatus("扫描中", "scan_pass") : getNextStatus("扫描中", "scan_fail");
    skill.scan = result.scan;
    skill.version = skill.status === "已发布" ? nextVersion(skill.version) : skill.version;
    skill.updatedAt = "刚刚";
    saveSkills();
    toast(result.summary.passed ? "安全审核通过，技能已自动发布" : "安全审核未通过，请修复后再发布");
    render();
  }, 900);
}

function nextVersion(version) {
  const match = String(version || "v0.0.0").match(/^v(\d+)\.(\d+)\.(\d+)$/);
  if (!match) return "v1.0.0";
  return `v${match[1]}.${match[2]}.${Number(match[3]) + 1}`;
}

function updateStatus(id, action, message) {
  const skill = state.skills.find(item => item.id === id);
  if (!skill) return;
  skill.status = getNextStatus(skill.status, action);
  skill.updatedAt = "刚刚";
  saveSkills();
  toast(message);
  render();
}

function removeSkill(id) {
  const skill = state.skills.find(item => item.id === id);
  if (!skill) return;
  if (skill.status === "扫描中") {
    toast("安全审核中不可删除，请等待审核完成");
    return;
  }
  if (skill.status === "已发布") {
    toast("已发布的技能不可直接删除，请先下架");
    return;
  }
  if (skill.status === "已下架" && skill.agents > 0) {
    toast("已有智能体引用此技能，请先解除引用后再删除");
    return;
  }
  state.skills = state.skills.filter(item => item.id !== id);
  state.page = "library";
  state.detailId = "";
  saveSkills();
  toast("技能已删除");
  render();
}

function copyOfficial(id) {
  const original = state.skills.find(item => item.id === id);
  if (!original) return;
  const copy = {
    ...original,
    id: `sk-${Date.now()}`,
    owner: "space",
    source: "官方复制",
    status: "草稿",
    skillId: `${original.skillId}_copy`,
    name: `${original.name} 副本`,
    agents: 0,
    creator: "jingxiu.zhao",
    updatedAt: "刚刚"
  };
  state.skills = [copy, ...state.skills];
  state.primaryTab = "space";
  state.page = "editor";
  state.editingId = copy.id;
  state.createMode = copy.source;
  saveSkills();
  toast("已复制到空间，请在编辑页确认后发布");
  render();
}

async function copyId(text) {
  await navigator.clipboard?.writeText(text);
  toast(`已复制 ${text}`);
}

function toast(text) {
  const el = document.createElement("div");
  el.className = "toast";
  el.textContent = text;
  document.body.appendChild(el);
  setTimeout(() => el.remove(), 2400);
}

function escapeHtml(text) {
  return String(text || "")
    .replaceAll("&", "&amp;")
    .replaceAll("<", "&lt;")
    .replaceAll(">", "&gt;")
    .replaceAll('"', "&quot;");
}

function escapeAttr(text) {
  return escapeHtml(text).replaceAll("'", "&#39;");
}

render();

